-- Update ABC agent with enhanced Educational Focus Image badge requirements
UPDATE agents
SET instructions = regexp_replace(
  instructions,
  'Educational Focus Image.*?(?=\*\*Page)',
  E'Educational Focus Image:\n\n**BADGE FORMAT (CRITICAL - MUST FOLLOW EXACTLY):**\nThe Educational Focus page MUST display THREE distinct colorful badges arranged vertically on a clean background. Each badge is a separate visual element with specific content:\n\n**Badge 1 - Age Range:**\n- Shape: Rounded rectangle or circle\n- Color: Teal/turquoise background (#20B2AA to #40E0D0)\n- Icon: Small book or ABC blocks icon\n- Text: "[X-Y years]" (use actual age range from user selection)\n- Example: "2-3 years"\n\n**Badge 2 - Learning Type:**\n- Shape: Rounded rectangle or circle  \n- Color: Coral/orange background (#FF6B6B to #FF8C69)\n- Icon: Small star or lightbulb icon\n- Text: "Alphabet Recognition"\n- This text is FIXED for all ABC books\n\n**Badge 3 - Skill Focus:**\n- Shape: Rounded rectangle or circle\n- Color: Gold/yellow background (#FFD700 to #FFA500)\n- Icon: Small trophy or checkmark icon\n- Text: "[Letter Case] Letters" (use actual case from user selection)\n- Examples: "lowercase letters", "UPPERCASE LETTERS", "Mixed Case Letters"\n\n**THEME INTEGRATION (when character theme selected):**\nIf user selected a character theme, use theme-appropriate badge shapes:\n- Mickey Mouse: Mickey ear shapes for badges\n- Paw Patrol: Shield shapes for badges\n- Peppa Pig: Round pig face shapes for badges\n- Frozen: Snowflake shapes for badges\n- Bluey: Rounded square shapes for badges\n- Other themes: Use rounded rectangles\n- No Theme: Use simple rounded rectangles or circles\n\n**BACKGROUND:**\n- Clean gradient background (light blue to white, or cream to white)\n- OR solid white background\n- NO character illustrations on this page\n- NO additional text or decorative elements\n\n**COMPOSITION:**\n- Three badges stacked vertically with even spacing\n- Center-aligned on the page\n- Each badge clearly visible and readable\n- Badges should be roughly same size\n- Clean, minimalist design focused on the badges only\n\n**COMPLETE EXAMPLE PROMPTS:**\n\nExample 1 (with Paw Patrol theme, lowercase, age 2-3):\n"Three colorful Paw Patrol shield-shaped badges stacked vertically on a clean light blue gradient background. Top badge is teal with small book icon and text \'2-3 years\'. Middle badge is coral with small star icon and text \'Alphabet Recognition\'. Bottom badge is gold with small trophy icon and text \'lowercase letters\'. Center-aligned, even spacing, minimalist design. No characters. No text overlays. Clean illustration only."\n\nExample 2 (with Mickey Mouse theme, uppercase, age 3-4):\n"Three colorful Mickey Mouse ear-shaped badges stacked vertically on a clean white background. Top badge is turquoise with small ABC blocks icon and text \'3-4 years\'. Middle badge is orange with small lightbulb icon and text \'Alphabet Recognition\'. Bottom badge is yellow with small checkmark icon and text \'UPPERCASE LETTERS\'. Center-aligned, even spacing, minimalist design. No characters. No text overlays. Clean illustration only."\n\nExample 3 (no theme, mixed case, age 4-5):\n"Three colorful rounded rectangle badges stacked vertically on a soft cream to white gradient background. Top badge is teal with small book icon and text \'4-5 years\'. Middle badge is coral with small star icon and text \'Alphabet Recognition\'. Bottom badge is gold with small trophy icon and text \'Mixed Case Letters\'. Center-aligned, even spacing, minimalist design. No text overlays. Clean illustration only."\n\n**VALIDATION RULES:**\n- Prompt MUST include all three badge descriptions\n- Prompt MUST use the actual age range from user selection\n- Prompt MUST use the actual letter case focus from user selection\n- Prompt MUST end with "No text overlays. Clean illustration only."\n- Prompt MUST NOT include character illustrations\n- If validation fails, REGENERATE the prompt\n\n',
  'sg'
)
WHERE id = '0b624dec-0eb3-4656-ba6f-0219297e3e11'
  AND type = 'book-creation-abc';
